INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('halloween','vous','long','La magie de la nuit et les frissons','Joyeux Halloween {annee} ! Aujourd''hui, c''est le moment de célébrer la magie de la nuit, les frissons des histoires effrayantes et la joie des bonbons. Que cette soirée soit aussi inoubliable que votre sourire, aussi mystérieuse que votre déguisement, et aussi amusante que vos rires. Que chaque instant passé avec ceux que vous aimez soit une nouvelle raison de croire en la magie d''Halloween. Que {annee} vous apporte tout ce que vous désirez : des frissons, des rires et des souvenirs précieux. Que chaque moment soit aussi spécial que cette nuit unique, et que chaque bonbon soit aussi doux que votre cœur.',true),
('halloween','vous','long','Le symbole de tout ce qui rend cette fête magique','Que cette Halloween {annee} soit bien plus qu''une simple soirée : qu''elle soit le symbole de tout ce qui rend cette fête magique. Que chaque moment soit rempli de surprises, de frissons et de joie. Que cette nuit vous rappelle à quel point il est amusant de jouer avec la peur, et que chaque instant soit aussi précieux que les bonbons que vous récoltez. Joyeux Halloween, et que cette année soit aussi effrayante et amusante que votre imagination.',true),
('halloween','vous','long','Vous déguiser et rire avec ceux que vous aimez','Halloween {annee}, c''est l''occasion de vous déguiser, de rire et de vous faire peur avec ceux que vous aimez. Que cette soirée soit aussi joyeuse que vos rires, aussi mystérieuse que la nuit, et aussi lumineuse que les citrouilles qui brillent. Que chaque instant soit une nouvelle aventure à vivre, et que chaque frisson soit aussi doux que votre cœur. Joyeux Halloween, et que cette année vous apporte tout ce que vous méritez.',true),
('halloween','vous','long','Tout ce qui rend cette fête unique','Aujourd''hui, c''est Halloween {annee}, et avec elle, l''occasion de célébrer tout ce qui rend cette fête unique. Que cette soirée soit remplie de moments inoubliables, de rires et de surprises. Que chaque instant soit une nouvelle preuve de la magie qui vous entoure. Joyeux Halloween, et que cette année soit aussi exceptionnelle que vous.',true),
('halloween','vous','long','Aussi précieux que l''or','Que cette Halloween {annee} soit le début d''une nuit remplie de joie, de mystère et de bonbons. Que chaque moment passé avec ceux que vous aimez soit aussi précieux que l''or, et que chaque rire soit aussi lumineux que les étoiles. Joyeux Halloween, et que cette fête soit aussi magique que vos rêves.',true),
('halloween','vous','long','Un conte qui prend vie','Halloween {annee}, c''est comme un conte qui prend vie : les déguisements, les bonbons et les frissons. Que cette soirée soit aussi douce que vos rêves, aussi effrayante que les histoires que vous aimez, et aussi joyeuse que vos rires. Que chaque instant soit une nouvelle raison de croire en la magie d''Halloween. Joyeux Halloween, et que cette année vous apporte tout ce que vous désirez.',true),
('halloween','vous','long','Remplie de lumière, de mystère et de joie','Que cette Halloween {annee} soit remplie de lumière, de mystère et de joie. Que chaque moment soit une nouvelle aventure à partager avec ceux qui comptent pour vous. Que cette soirée soit aussi belle que votre âme, et que chaque instant soit aussi précieux que votre cœur. Joyeux Halloween !',true),
('halloween','vous','long','Ce qui rend cette nuit spéciale','Aujourd''hui, c''est Halloween {annee}, et c''est l''occasion de célébrer tout ce qui rend cette nuit spéciale. Que cette soirée soit aussi joyeuse que vos rires, aussi mystérieuse que la lune, et aussi douce que vos rêves. Que chaque instant soit une nouvelle raison de sourire, et que cette année soit aussi exceptionnelle que vous.',true),
('halloween','vous','long','Des souvenirs aussi beaux','Que cette Halloween {annee} soit une fête remplie de magie, de frissons et de moments précieux. Que chaque instant soit aussi beau que les souvenirs que vous créez, et que chaque moment soit une nouvelle preuve de la joie qui vous entoure. Joyeux Halloween, et que cette année soit aussi belle que votre cœur.',true),
